defmodule DevopsAutomation.CommandService do
  @moduledoc """
  Safe command execution service using an allowlist of permitted commands.
  NEVER pass raw user input to System.cmd with "sh -c".
  """

  # Allowlist of permitted commands with their allowed argument patterns
  @allowed_commands %{
    "disk_usage" => {"/usr/bin/df", ["-h"]},
    "memory_info" => {"/usr/bin/free", ["-m"]},
    "uptime" => {"/usr/bin/uptime", []},
    "list_containers" => {"/usr/bin/docker", ["ps", "--format", "table {{.Names}}\t{{.Status}}"]},
    "service_status" => {"/usr/bin/systemctl", ["status"]},
    "ping" => {"/usr/bin/ping", ["-c", "4"]}
  }

  @doc """
  Executes a pre-approved command by name with optional validated arguments.
  Returns {:ok, output} or {:error, reason}.
  """
  def execute(command_name, extra_args \\ []) when is_binary(command_name) do
    with {:ok, {executable, base_args}} <- lookup_command(command_name),
         {:ok, validated_args} <- validate_args(command_name, extra_args) do
      args = base_args ++ validated_args

      try do
        {output, exit_code} =
          System.cmd(executable, args,
            stderr_to_stdout: true,
            env: [{"PATH", "/usr/bin:/usr/local/bin"}],
            # Kill command after 30 seconds
            timeout: 30_000
          )

        case exit_code do
          0 -> {:ok, %{output: output, exit_code: 0}}
          code -> {:error, %{output: output, exit_code: code}}
        end
      rescue
        e in ErlangError ->
          {:error, %{reason: "Command execution failed: #{inspect(e)}"}}
      end
    end
  end

  defp lookup_command(name) do
    case Map.fetch(@allowed_commands, name) do
      {:ok, cmd} -> {:ok, cmd}
      :error -> {:error, %{reason: "Command '#{name}' is not in the allowlist"}}
    end
  end

  # Validate extra arguments - no shell metacharacters, no path traversal
  defp validate_args(command_name, args) when is_list(args) do
    if Enum.all?(args, &safe_argument?/1) do
      validate_args_for_command(command_name, args)
    else
      {:error, %{reason: "Arguments contain forbidden characters"}}
    end
  end

  defp validate_args(_command_name, _args) do
    {:error, %{reason: "Arguments must be a list of strings"}}
  end

  defp safe_argument?(arg) when is_binary(arg) do
    # Reject shell metacharacters, pipes, redirects, backticks, etc.
    not Regex.match?(~r/[;&|`$(){}\[\]<>!\\#~*?]/, arg) and
      # Reject path traversal
      not String.contains?(arg, "..") and
      # Reasonable length limit
      String.length(arg) <= 256
  end

  defp safe_argument?(_), do: false

  # Command-specific argument validation
  defp validate_args_for_command("service_status", [service_name]) do
    if Regex.match?(~r/\A[a-zA-Z0-9_\-\.]+\z/, service_name) do
      {:ok, [service_name]}
    else
      {:error, %{reason: "Invalid service name"}}
    end
  end

  defp validate_args_for_command("service_status", _),
    do: {:error, %{reason: "service_status requires exactly one service name"}}

  defp validate_args_for_command("ping", [hostname]) do
    if Regex.match?(~r/\A[a-zA-Z0-9\.\-]+\z/, hostname) do
      {:ok, [hostname]}
    else
      {:error, %{reason: "Invalid hostname"}}
    end
  end

  defp validate_args_for_command("ping", _),
    do: {:error, %{reason: "ping requires exactly one hostname"}}

  # Commands that take no extra args
  defp validate_args_for_command(_command, []), do: {:ok, []}

  defp validate_args_for_command(command, _args),
    do: {:error, %{reason: "Command '#{command}' does not accept extra arguments"}}

  def list_available_commands do
    Map.keys(@allowed_commands)
  end
end

defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  plug :authorize_user

  def index(conn, _params) do
    commands = CommandService.list_available_commands()
    json(conn, %{available_commands: commands})
  end

  def execute(conn, %{"command" => command_name} = params) do
    extra_args = Map.get(params, "args", [])

    # Audit log
    Logger.info("Command execution requested",
      command: command_name,
      args: extra_args,
      user: conn.assigns[:current_user],
      ip: to_string(:inet_parse.ntoa(conn.remote_ip))
    )

    case CommandService.execute(command_name, extra_args) do
      {:ok, result} ->
        json(conn, %{status: "success", data: result})

      {:error, %{reason: reason}} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: reason})

      {:error, %{output: output, exit_code: code}} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{status: "error", exit_code: code, output: output})
    end
  end

  def execute(conn, _params) do
    conn
    |> put_status(:bad_request)
    |> json(%{status: "error", message: "Missing required 'command' parameter"})
  end

